     1→/**
     2→ * Email Processing Orchestrator (T040)
     3→ *
     4→ * Coordinates batch processing of emails through the complete pipeline:
     5→ * 1. Fetch emails from Gmail API
     6→ * 2. Classify using classification engine
     7→ * 3. Persist results to database
     8→ *
     9→ * Features:
    10→ * - Batch processing with error resilience
    11→ * - Performance metrics tracking
    12→ * - Configurable batch options (max emails, date ranges)
    13→ * - Graceful error handling (continue on individual failures)
    14→ */
    15→
    16→import {
    17→  type EmailMessage,
    18→  type ClassificationResult,
    19→  type ProcessingConfig,
    20→} from '@gmail-automation/classification-engine';
    21→
    22→/**
    23→ * Gmail client interface for email fetching
    24→ * Full implementation in T037-T038
    25→ */
    26→export interface GmailClient {
    27→  /**
    28→   * Fetch emails with optional filters
    29→   */
    30→  fetchEmails(options: FetchOptions): Promise<EmailMessage[]>;
    31→
    32→  /**
    33→   * Fetch single email by ID
    34→   */
    35→  fetchEmailById(messageId: string): Promise<EmailMessage>;
    36→}
    37→
    38→/**
    39→ * Classification orchestrator interface for cross-package integration
    40→ * Full implementation in T041
    41→ */
    42→export interface ClassificationOrchestrator {
    43→  /**
    44→   * Classify batch of emails
    45→   */
    46→  classifyBatch(emails: EmailMessage[]): Promise<Array<ClassificationResult | ClassificationErrorResult>>;
    47→
    48→  /**
    49→   * Classify single email
    50→   */
    51→  classify(email: EmailMessage): Promise<ClassificationResult>;
    52→}
    53→
    54→/**
    55→ * Persistence interface for saving classification results
    56→ * Uses existing T036j implementation (classification-writer.ts)
    57→ */
    58→export interface PersistenceService {
    59→  /**
    60→   * Save batch of classification results
    61→   */
    62→  saveClassificationBatch(results: Map<string, ClassificationResult>): Promise<void>;
    63→
    64→  /**
    65→   * Save single classification result
    66→   */
    67→  saveClassificationResult(messageId: string, result: ClassificationResult): Promise<void>;
    68→}
    69→
    70→/**
    71→ * Classification error result for batch processing
    72→ */
    73→export interface ClassificationErrorResult {
    74→  error: Error;
    75→  emailId: string;
    76→  processingDurationMs: number;
    77→}
    78→
    79→/**
    80→ * Options for fetching emails
    81→ */
    82→export interface FetchOptions {
    83→  maxEmails?: number;
    84→  startDate?: Date;
    85→  endDate?: Date;
    86→  unclassifiedOnly?: boolean;
    87→}
    88→
    89→/**
    90→ * Result of batch processing operation
    91→ */
    92→export interface BatchProcessingResult {
    93→  totalProcessed: number;
    94→  successCount: number;
    95→  errorCount: number;
    96→  processingDurationMs: number;
    97→  averageEmailDurationMs: number;
    98→  errors: Array<{
    99→    emailId: string;
   100→    error: Error;
   101→  }>;
   102→}
   103→
   104→/**
   105→ * Result of single email processing
   106→ */
   107→export interface SingleProcessingResult {
   108→  success: boolean;
   109→  emailId: string;
   110→  classificationResult?: ClassificationResult;
   111→  error?: Error;
   112→  processingDurationMs: number;
   113→}
   114→
   115→/**
   116→ * Email Processing Orchestrator
   117→ *
   118→ * Main service coordinating email processing pipeline with error handling
   119→ * and performance tracking.
   120→ */
   121→export class EmailProcessor {
   122→  private readonly gmailClient: GmailClient;
   123→  private readonly classificationOrchestrator: ClassificationOrchestrator;
   124→  private readonly persistence: PersistenceService;
   125→  private readonly config: ProcessingConfig;
   126→
   127→  /**
   128→   * Initialize email processor with dependencies
   129→   *
   130→   * @param gmailClient - Gmail API client for fetching emails
   131→   * @param classificationOrchestrator - Classification engine orchestrator
   132→   * @param persistence - Persistence service for saving results
   133→   * @param config - Processing configuration
   134→   * @throws {Error} If configuration validation fails
   135→   */
   136→  constructor(
   137→    gmailClient: GmailClient,
   138→    classificationOrchestrator: ClassificationOrchestrator,
   139→    persistence: PersistenceService,
   140→    config: ProcessingConfig
   141→  ) {
   142→    // Validate configuration
   143→    this.validateConfig(config);
   144→
   145→    this.gmailClient = gmailClient;
   146→    this.classificationOrchestrator = classificationOrchestrator;
   147→    this.persistence = persistence;
   148→    this.config = config;
   149→  }
   150→
   151→  /**
   152→   * Validate processing configuration
   153→   *
   154→   * @param config - Configuration to validate
   155→   * @throws {Error} If configuration is invalid
   156→   */
   157→  private validateConfig(config: ProcessingConfig): void {
   158→    if (!config) {
   159→      throw new Error('Invalid configuration: config is required');
   160→    }
   161→
   162→    if (!config.confidenceThresholds) {
   163→      throw new Error('Invalid configuration: confidenceThresholds is required');
   164→    }
   165→
   166→    if (!config.settings) {
   167→      throw new Error('Invalid configuration: settings is required');
   168→    }
   169→
   170→    // Validate required nested settings
   171→    if (!config.settings.multiLabelSelection) {
   172→      throw new Error('Invalid configuration: settings.multiLabelSelection is required');
   173→    }
   174→
   175→    if (!config.multiLabelPolicy) {
   176→      throw new Error('Invalid configuration: multiLabelPolicy is required');
   177→    }
   178→  }
   179→
   180→  /**
   181→   * Process batch of emails through complete pipeline
   182→   *
   183→   * Workflow:
   184→   * 1. Fetch emails from Gmail
   185→   * 2. Classify emails in batch
   186→   * 3. Persist successful results
   187→   * 4. Return summary with errors
   188→   *
   189→   * @param options - Fetch options for email retrieval
   190→   * @returns Batch processing result with metrics
   191→   */
   192→  async processBatch(options: FetchOptions): Promise<BatchProcessingResult> {
   193→    const startTime = Date.now();
   194→    const errors: Array<{ emailId: string; error: Error }> = [];
   195→
   196→    try {
   197→      // 1. Fetch emails
   198→      const emails = await this.gmailClient.fetchEmails(options);
   199→
   200→      if (emails.length === 0) {
   201→        return {
   202→          totalProcessed: 0,
   203→          successCount: 0,
   204→          errorCount: 0,
   205→          processingDurationMs: Date.now() - startTime,
   206→          averageEmailDurationMs: 0,
   207→          errors: [],
   208→        };
   209→      }
   210→
   211→      // 2. Classify emails in batch
   212→      const classificationResults = await this.classificationOrchestrator.classifyBatch(emails);
   213→
   214→      // 3. Separate successful results from errors
   215→      const successfulResults = new Map<string, ClassificationResult>();
   216→
   217→      classificationResults.forEach((result, index) => {
   218→        if ('error' in result) {
   219→          // Classification failed for this email
   220→          errors.push({
   221→            emailId: result.emailId,
   222→            error: result.error,
   223→          });
   224→        } else {
   225→          // Classification succeeded
   226→          successfulResults.set(emails[index].id, result);
   227→        }
   228→      });
   229→
   230→      // 4. Persist successful results
   231→      if (successfulResults.size > 0) {
   232→        await this.persistence.saveClassificationBatch(successfulResults);
   233→      }
   234→
   235→      // 5. Calculate metrics
   236→      const endTime = Date.now();
   237→      const totalDuration = endTime - startTime;
   238→      const totalProcessed = emails.length;
   239→      const successCount = successfulResults.size;
   240→      const errorCount = errors.length;
   241→      const averageEmailDurationMs = totalProcessed > 0 ? totalDuration / totalProcessed : 0;
   242→
   243→      return {
   244→        totalProcessed,
   245→        successCount,
   246→        errorCount,
   247→        processingDurationMs: totalDuration,
   248→        averageEmailDurationMs,
   249→        errors,
   250→      };
   251→    } catch (error) {
   252→      // Fatal error during batch processing
   253→      throw new Error(`Batch processing failed: ${error instanceof Error ? error.message : String(error)}`);
   254→    }
