/**
 * Unit tests for EmailRepository (T042)
 *
 * Test-driven development approach for email persistence layer with batch operations.
 * Tests cover: batch insert, batch update, upsert, query operations, transaction handling.
 */

import { Pool } from 'pg';
import { EmailMessage, EmailAddress } from '@gmail-automation/classification-engine';
import { EmailRepository } from '../../src/persistence/email-repository';

// Mock pg.Pool
jest.mock('pg', () => {
  const mockClient = {
    query: jest.fn(),
    release: jest.fn(),
  };

  const mockPool = {
    query: jest.fn(),
    connect: jest.fn(() => Promise.resolve(mockClient)),
    end: jest.fn(() => Promise.resolve()),
  };

  return {
    Pool: jest.fn(() => mockPool),
  };
});

describe('EmailRepository', () => {
  let repository: EmailRepository;
  let mockPool: jest.Mocked<Pool>;

  beforeEach(() => {
    jest.clearAllMocks();

    // Create repository with mocked pool
    mockPool = new Pool() as jest.Mocked<Pool>;
    repository = new EmailRepository(mockPool);
  });

  afterEach(async () => {
    await repository.close();
  });

  describe('constructor', () => {
    it('should create repository with provided pool', () => {
      expect(repository).toBeInstanceOf(EmailRepository);
    });

    it('should create repository with default pool if none provided', () => {
      const defaultRepo = new EmailRepository();
      expect(defaultRepo).toBeInstanceOf(EmailRepository);
    });
  });

  describe('batchInsert', () => {
    it('should insert multiple emails in a single transaction', async () => {
      const emails: EmailMessage[] = [
        createMockEmail('msg1', 'thread1', 'test1@example.com'),
        createMockEmail('msg2', 'thread2', 'test2@example.com'),
      ];

      const mockClient = {
        query: jest.fn().mockResolvedValue({ rows: [] }),
        release: jest.fn(),
      };
      mockPool.connect.mockResolvedValue(mockClient as any);

      await repository.batchInsert(emails);

      // Verify transaction was used
      expect(mockPool.connect).toHaveBeenCalled();
      expect(mockClient.query).toHaveBeenCalledWith('BEGIN');
      expect(mockClient.query).toHaveBeenCalledWith('COMMIT');
      expect(mockClient.release).toHaveBeenCalled();

      // Verify INSERT statement was called for each email
      const insertCalls = mockClient.query.mock.calls.filter((call) => call[0].includes('INSERT'));
      expect(insertCalls.length).toBe(2);
    });

    it('should rollback transaction on error', async () => {
      const emails: EmailMessage[] = [createMockEmail('msg1', 'thread1', 'test@example.com')];

      const mockClient = {
        query: jest.fn().mockImplementation((query: string) => {
          if (query.includes('INSERT')) {
            throw new Error('Database error');
          }
          return Promise.resolve({ rows: [] });
        }),
        release: jest.fn(),
      };
      mockPool.connect.mockResolvedValue(mockClient as any);

      await expect(repository.batchInsert(emails)).rejects.toThrow('Failed to batch insert emails');

      // Verify rollback was called
      expect(mockClient.query).toHaveBeenCalledWith('ROLLBACK');
      expect(mockClient.release).toHaveBeenCalled();
    });

    it('should handle empty email array gracefully', async () => {
      await repository.batchInsert([]);

      // Should not attempt to connect to database
      expect(mockPool.connect).not.toHaveBeenCalled();
    });

    it('should handle duplicate gmail_id constraint violations', async () => {
      const emails: EmailMessage[] = [createMockEmail('msg1', 'thread1', 'test@example.com')];

      const mockClient = {
        query: jest.fn().mockImplementation((query: string) => {
          if (query.includes('INSERT')) {
            const error: any = new Error('duplicate key value violates unique constraint');
            error.code = '23505'; // PostgreSQL unique violation code
            throw error;
          }
          return Promise.resolve({ rows: [] });
        }),
        release: jest.fn(),
      };
      mockPool.connect.mockResolvedValue(mockClient as any);

      await expect(repository.batchInsert(emails)).rejects.toThrow();
      expect(mockClient.query).toHaveBeenCalledWith('ROLLBACK');
    });

    it('should insert email with all fields correctly mapped', async () => {
      const email = createMockEmail('msg1', 'thread1', 'test@example.com', {
        subject: 'Test Subject',
        bodyHtml: '<p>Test HTML</p>',
        bodyPlain: 'Test Plain',
        gmailLabels: ['INBOX', 'UNREAD'],
        snippet: 'Test snippet',
        sizeEstimate: 1234,
        processingBatch: 'batch-123',
        processingPriority: 5,
      });

      const mockClient = {
        query: jest.fn().mockResolvedValue({ rows: [] }),
        release: jest.fn(),
      };
      mockPool.connect.mockResolvedValue(mockClient as any);

      await repository.batchInsert([email]);

      // Verify the INSERT statement includes all expected columns
      const insertCall = mockClient.query.mock.calls.find((call) => call[0].includes('INSERT'));
      expect(insertCall).toBeDefined();
      expect(insertCall![0]).toContain('gmail_id');
      expect(insertCall![0]).toContain('gmail_thread_id');
      expect(insertCall![0]).toContain('subject');
      expect(insertCall![0]).toContain('body_html');
      expect(insertCall![0]).toContain('body_text');
      expect(insertCall![0]).toContain('label_ids');
      expect(insertCall![0]).toContain('processing_batch');
      expect(insertCall![0]).toContain('processing_priority');
    });
  });

  describe('batchUpdateMetadata', () => {
    it('should update processing metadata for multiple emails', async () => {
      const updates = [
        { gmailId: 'msg1', isProcessed: true, processedAt: new Date() },
        { gmailId: 'msg2', isProcessed: true, processedAt: new Date() },
      ];

      const mockClient = {
        query: jest.fn().mockResolvedValue({ rows: [] }),
        release: jest.fn(),
      };
      mockPool.connect.mockResolvedValue(mockClient as any);

      await repository.batchUpdateMetadata(updates);

      // Verify transaction was used
      expect(mockClient.query).toHaveBeenCalledWith('BEGIN');
      expect(mockClient.query).toHaveBeenCalledWith('COMMIT');

      // Verify UPDATE statements
      const updateCalls = mockClient.query.mock.calls.filter((call) => call[0].includes('UPDATE'));
      expect(updateCalls.length).toBe(2);
    });

    it('should handle empty updates array gracefully', async () => {
      await repository.batchUpdateMetadata([]);

      expect(mockPool.connect).not.toHaveBeenCalled();
    });
  });

  describe('upsert', () => {
    it('should insert new email if not exists', async () => {
      const email = createMockEmail('msg1', 'thread1', 'test@example.com');

      mockPool.query.mockResolvedValue({ rows: [], rowCount: 0 } as any);

      await repository.upsert(email);

      // Should perform INSERT ON CONFLICT UPDATE
      expect(mockPool.query).toHaveBeenCalled();
      const query = mockPool.query.mock.calls[0][0];
      expect(query).toContain('INSERT');
      expect(query).toContain('ON CONFLICT');
      expect(query).toContain('DO UPDATE');
    });

    it('should update existing email if already exists', async () => {
      const email = createMockEmail('msg1', 'thread1', 'test@example.com');

      mockPool.query.mockResolvedValue({ rows: [], rowCount: 1 } as any);

      await repository.upsert(email);

      expect(mockPool.query).toHaveBeenCalled();
    });
  });

  describe('getLastEmailTimestamp', () => {
    it('should return the most recent email timestamp', async () => {
      const expectedDate = new Date('2024-01-15T10:30:00Z');

      mockPool.query.mockResolvedValue({
        rows: [{ sent_at: expectedDate }],
        rowCount: 1,
      } as any);

      const result = await repository.getLastEmailTimestamp();

      expect(result).toEqual(expectedDate);
      expect(mockPool.query).toHaveBeenCalledWith(expect.stringContaining('SELECT MAX(sent_at)'), expect.any(Array));
    });

    it('should return null if no emails exist', async () => {
      mockPool.query.mockResolvedValue({
        rows: [],
        rowCount: 0,
      } as any);

      const result = await repository.getLastEmailTimestamp();

      expect(result).toBeNull();
    });
  });

  describe('markAsProcessed', () => {
    it('should mark multiple emails as processed', async () => {
      const gmailIds = ['msg1', 'msg2', 'msg3'];
      const processingBatch = 'batch-123';

      mockPool.query.mockResolvedValue({ rows: [], rowCount: 3 } as any);

      await repository.markAsProcessed(gmailIds, processingBatch);

      expect(mockPool.query).toHaveBeenCalled();
      const query = mockPool.query.mock.calls[0][0];
      expect(query).toContain('UPDATE');
      expect(query).toContain('is_processed');
      expect(query).toContain('processed_at');
    });

    it('should handle empty gmailIds array gracefully', async () => {
      await repository.markAsProcessed([], 'batch-123');

      expect(mockPool.query).not.toHaveBeenCalled();
    });
  });

  describe('findUnprocessed', () => {
    it('should return unprocessed emails with default limit', async () => {
      const mockEmails = [
        {
          gmail_id: 'msg1',
          gmail_thread_id: 'thread1',
          subject: 'Test 1',
          sent_at: new Date(),
          label_ids: ['INBOX'],
          from_simple: JSON.stringify({ email: 'test1@example.com', raw: 'test1@example.com' }),
          to_addrs: JSON.stringify([{ email: 'recipient@example.com', raw: 'recipient@example.com' }]),
          headers: JSON.stringify([]),
          raw: JSON.stringify({}),
          is_processed: false,
        },
      ];

      mockPool.query.mockResolvedValue({
        rows: mockEmails,
        rowCount: 1,
      } as any);

      const result = await repository.findUnprocessed();

      expect(result).toHaveLength(1);
      expect(result[0].id).toBe('msg1');
      expect(mockPool.query).toHaveBeenCalledWith(expect.stringContaining('is_processed = false'), expect.any(Array));
    });

    it('should respect custom limit parameter', async () => {
      mockPool.query.mockResolvedValue({
        rows: [],
        rowCount: 0,
      } as any);

      await repository.findUnprocessed({ limit: 50 });

      expect(mockPool.query).toHaveBeenCalledWith(expect.any(String), [50]);
    });

    it('should filter by date range if provided', async () => {
      const startDate = new Date('2024-01-01');
      const endDate = new Date('2024-01-31');

      mockPool.query.mockResolvedValue({
        rows: [],
        rowCount: 0,
      } as any);

      await repository.findUnprocessed({ startDate, endDate, limit: 100 });

      const query = mockPool.query.mock.calls[0][0];
      expect(query).toContain('sent_at >= $2');
      expect(query).toContain('sent_at <= $3');
    });
  });

  describe('close', () => {
    it('should close the database pool', async () => {
      await repository.close();

      expect(mockPool.end).toHaveBeenCalled();
    });
  });
});

/**
 * Helper function to create mock EmailMessage objects for testing
 */
function createMockEmail(
  id: string,
  threadId: string,
  fromEmail: string,
  overrides: Partial<EmailMessage> = {}
): EmailMessage {
  const from: EmailAddress = {
    email: fromEmail,
    name: 'Test Sender',
    raw: `Test Sender <${fromEmail}>`,
  };

  const to: EmailAddress[] = [
    {
      email: 'recipient@example.com',
      name: 'Test Recipient',
      raw: 'Test Recipient <recipient@example.com>',
    },
  ];

  return {
    id,
    threadId,
    gmailLabels: ['INBOX'],
    payload: {
      mimeType: 'text/plain',
      headers: [
        { name: 'From', value: from.raw },
        { name: 'To', value: to[0].raw },
        { name: 'Subject', value: 'Test Subject' },
        { name: 'Date', value: new Date().toISOString() },
      ],
      body: {
        data: 'VGVzdCBib2R5IGNvbnRlbnQ=', // Base64 encoded "Test body content"
