      whereClauses.push(`processing_batch = $${paramIndex}`);
      values.push(processingBatch);
      paramIndex++;
    }

    const query = `
      SELECT
        gmail_id,
        gmail_thread_id,
        label_ids,
        subject,
        sent_at,
        message_id_hdr,
        from_simple,
        to_addrs,
        reply_to_addrs,
        headers,
        body_text,
        body_html,
        raw,
        size_estimate,
        processing_batch,
        processing_priority,
        is_processed,
        processed_at
      FROM email.gmail_message
      WHERE ${whereClauses.join(' AND ')}
      ORDER BY sent_at DESC
      LIMIT $1
    `;

    try {
      const result = await this.pool.query(query, values);
      return result.rows.map(this.mapRowToEmailMessage);
    } catch (error) {
      throw new Error(
        `Failed to find unprocessed emails: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Map database row to EmailMessage interface
   *
   * @param row - Database row from gmail_message table
   * @returns EmailMessage object
   */
  private mapRowToEmailMessage(row: any): EmailMessage {
    // Parse JSON fields
    const fromSimple = typeof row.from_simple === 'string' ? JSON.parse(row.from_simple) : row.from_simple;
    const toAddrs = typeof row.to_addrs === 'string' ? JSON.parse(row.to_addrs) : row.to_addrs;
    const headers = typeof row.headers === 'string' ? JSON.parse(row.headers) : row.headers;
    const raw = typeof row.raw === 'string' ? JSON.parse(row.raw) : row.raw;
