      : undefined;

    return {
      id: row.gmail_id,
      threadId: row.gmail_thread_id,
      gmailLabels: row.label_ids || [],
      payload: raw.payload || {
        mimeType: 'text/plain',
        headers: headers,
      },
      subject: row.subject || '',
