/**
 * Unit tests for EmailRepository (T042)
 *
 * Test-driven development approach for email persistence layer with batch operations.
 * Tests cover: batch insert, batch update, upsert, query operations, transaction handling.
 */

import { Pool } from 'pg';
import { EmailMessage, EmailAddress } from '@gmail-automation/classification-engine';
import { EmailRepository } from '../../src/persistence/email-repository';

// Mock pg.Pool
jest.mock('pg', () => {
  const mockClient = {
    query: jest.fn(),
    release: jest.fn(),
  };

  const mockPool = {
    query: jest.fn(),
    connect: jest.fn(() => Promise.resolve(mockClient)),
    end: jest.fn(() => Promise.resolve()),
  };

  return {
    Pool: jest.fn(() => mockPool),
  };
});

describe('EmailRepository', () => {
  let repository: EmailRepository;
  let mockPool: jest.Mocked<Pool>;

  beforeEach(() => {
    jest.clearAllMocks();

    // Create repository with mocked pool
    mockPool = new Pool() as jest.Mocked<Pool>;
    repository = new EmailRepository(mockPool);
  });

  afterEach(async () => {
    await repository.close();
  });

  describe('constructor', () => {
    it('should create repository with provided pool', () => {
      expect(repository).toBeInstanceOf(EmailRepository);
    });

    it('should create repository with default pool if none provided', () => {
      const defaultRepo = new EmailRepository();
      expect(defaultRepo).toBeInstanceOf(EmailRepository);
    });
  });

  describe('batchInsert', () => {
    it('should insert multiple emails in a single transaction', async () => {
      const emails: EmailMessage[] = [
        createMockEmail('msg1', 'thread1', 'test1@example.com'),
        createMockEmail('msg2', 'thread2', 'test2@example.com'),
      ];

      const mockClient = {
        query: jest.fn().mockResolvedValue({ rows: [] }),
        release: jest.fn(),
      };
      mockPool.connect.mockResolvedValue(mockClient as any);

      await repository.batchInsert(emails);

      // Verify transaction was used
      expect(mockPool.connect).toHaveBeenCalled();
      expect(mockClient.query).toHaveBeenCalledWith('BEGIN');
      expect(mockClient.query).toHaveBeenCalledWith('COMMIT');
      expect(mockClient.release).toHaveBeenCalled();

      // Verify INSERT statement was called for each email
      const insertCalls = mockClient.query.mock.calls.filter((call) => call[0].includes('INSERT'));
      expect(insertCalls.length).toBe(2);
    });

    it('should rollback transaction on error', async () => {
      const emails: EmailMessage[] = [createMockEmail('msg1', 'thread1', 'test@example.com')];

      const mockClient = {
        query: jest.fn().mockImplementation((query: string) => {
          if (query.includes('INSERT')) {
            throw new Error('Database error');
          }
          return Promise.resolve({ rows: [] });
        }),
        release: jest.fn(),
      };
      mockPool.connect.mockResolvedValue(mockClient as any);

      await expect(repository.batchInsert(emails)).rejects.toThrow('Failed to batch insert emails');

      // Verify rollback was called
      expect(mockClient.query).toHaveBeenCalledWith('ROLLBACK');
