 */
function createMockEmail(
  id: string,
  threadId: string,
  fromEmail: string,
  overrides: Partial<EmailMessage> = {}
): EmailMessage {
  const from: EmailAddress = {
    email: fromEmail,
    name: 'Test Sender',
    raw: `Test Sender <${fromEmail}>`,
  };

  const to: EmailAddress[] = [
    {
      email: 'recipient@example.com',
      name: 'Test Recipient',
      raw: 'Test Recipient <recipient@example.com>',
