      body: {
        data: 'VGVzdCBib2R5IGNvbnRlbnQ=', // Base64 encoded "Test body content"
        size: 17,
      },
    },
    subject: 'Test Subject',
    from,
    to,
    date: new Date(),
    messageId: `${id}@mail.example.com`,
    bodyPlain: 'Test body content',
    snippet: 'Test snippet',
    sizeEstimate: 1234,
    isProcessed: false,
    processingPriority: 1,
    ...overrides,
  };
}

