   244→  async batchUpdateMetadata(updates: EmailMetadataUpdate[]): Promise<void> {
   245→    if (updates.length === 0) {
   246→      return; // Nothing to update
   247→    }
   248→
   249→    try {
   250→      await withTransaction(this.pool, async (client) => {
   251→        for (const update of updates) {
