   259→
   260→  /**
   261→   * Update metadata for single email
   262→   *
   263→   * @param client - Database client (for transaction support)
   264→   * @param update - Metadata update
   265→   */
   266→  private async updateSingleMetadata(client: PoolClient, update: EmailMetadataUpdate): Promise<void> {
   267→    const setClauses: string[] = [];
   268→    const values: unknown[] = [update.gmailId];
   269→    let paramIndex = 2;
   270→
   271→    if (update.isProcessed !== undefined) {
