   361→        processing_priority = EXCLUDED.processing_priority
   362→    `;
   363→
   364→    const values = [
   365→      email.id,
   366→      email.threadId,
   367→      email.sizeEstimate || null,
   368→      email.gmailLabels,
   369→      email.subject,
