      }),
      email.processingBatch || null,
      email.processingPriority,
      email.isProcessed,
    ];

    try {
      await this.pool.query(query, values);
    } catch (error) {
      throw new Error(`Failed to upsert email: ${error instanceof Error ? error.message : String(error)}`);
    }
  }

  /**
