   * });
   * ```
   */
  async getLastEmailTimestamp(): Promise<Date | null> {
    const query = `
      SELECT MAX(sent_at) as sent_at
      FROM email.gmail_message
    `;

    try {
      const result = await this.pool.query(query, []);

      if (result.rows.length === 0 || !result.rows[0].sent_at) {
        return null;
      }

      return new Date(result.rows[0].sent_at);
    } catch (error) {
      throw new Error(`Failed to get last email timestamp: ${error instanceof Error ? error.message : String(error)}`);
    }
