 * - T038b: EmailFetcher (batch email fetching)
 * - T042: EmailRepository (Prisma persistence)
 *
 * This CLI enables the milestone: "fetch new emails into gmail_messages table
 * since last recorded email timestamp in the database"
 */

import { PrismaClient } from '@prisma/client';
import { google } from 'googleapis';
import { EmailMessage } from '@gmail-automation/classification-engine';
import { GmailClient } from '../../src/gmail/gmail-client';
import { EmailFetcher } from '../../src/gmail/email-fetcher';
import { EmailRepository } from '../../src/persistence/email-repository';

// Mock dependencies
jest.mock('googleapis');
jest.mock('@prisma/client', () => {
  const mockPrismaClient = {
    gmailMessage: {
      upsert: jest.fn(),
      findFirst: jest.fn(),
    },
    $transaction: jest.fn(),
    $disconnect: jest.fn(),
  };

  return {
    PrismaClient: jest.fn(() => mockPrismaClient),
    Prisma: {
      JsonObject: {},
      JsonArray: [],
    },
  };
});

// Import the CLI function (to be implemented)
import { fetchAndPersistEmails } from '../../src/cli/fetch-emails';

describe('fetch-emails CLI (T042a)', () => {
  let mockPrisma: jest.Mocked<PrismaClient>;
  let mockGmailClient: jest.Mocked<GmailClient>;
  let mockEmailFetcher: jest.Mocked<EmailFetcher>;
  let repository: EmailRepository;

  beforeEach(() => {
    jest.clearAllMocks();

    // Setup mocked Prisma
    mockPrisma = new PrismaClient() as jest.Mocked<PrismaClient>;
    repository = new EmailRepository(mockPrisma);

    // Setup mocked Gmail client
    mockGmailClient = {
      listMessages: jest.fn(),
      getMessage: jest.fn(),
      isAuthenticated: jest.fn().mockReturnValue(true),
    } as unknown as jest.Mocked<GmailClient>;

    // Setup mocked Email fetcher
    mockEmailFetcher = {
      fetchEmails: jest.fn(),
      fetchEmailsSince: jest.fn(),
    } as unknown as jest.Mocked<EmailFetcher>;
  });

  describe('Incremental Email Fetching', () => {
    it('should fetch emails since last database timestamp', async () => {
      const lastTimestamp = new Date('2024-01-15T10:00:00Z');
      const mockEmails: EmailMessage[] = [
        createMockEmail('msg1', 'thread1', 'test1@example.com', new Date('2024-01-15T11:00:00Z')),
        createMockEmail('msg2', 'thread2', 'test2@example.com', new Date('2024-01-15T12:00:00Z')),
      ];

      // Mock repository to return last timestamp
      (mockPrisma.gmailMessage.findFirst as jest.Mock).mockResolvedValue({
        sentAt: lastTimestamp,
      });

      // Mock fetcher to return new emails
      mockEmailFetcher.fetchEmailsSince.mockResolvedValue(mockEmails);

      // Mock transaction for batch insert
      (mockPrisma.$transaction as jest.Mock).mockImplementation((operations) => {
        return Promise.all(operations.map(() => Promise.resolve()));
      });

      const result = await fetchAndPersistEmails({
        gmailClient: mockGmailClient,
        emailFetcher: mockEmailFetcher,
        repository,
      });

      // Verify last timestamp was queried
      expect(mockPrisma.gmailMessage.findFirst).toHaveBeenCalledWith({
        orderBy: { sentAt: 'desc' },
        select: { sentAt: true },
      });

      // Verify emails were fetched since last timestamp
      expect(mockEmailFetcher.fetchEmailsSince).toHaveBeenCalledWith(lastTimestamp);

      // Verify emails were persisted
      expect(mockPrisma.$transaction).toHaveBeenCalledTimes(1);

      // Verify result summary
      expect(result).toEqual({
        success: true,
        fetchedCount: 2,
        persistedCount: 2,
        sinceTimestamp: lastTimestamp,
        errors: [],
      });
    });

    it('should handle no previous emails (fetch all)', async () => {
      const mockEmails: EmailMessage[] = [createMockEmail('msg1', 'thread1', 'test@example.com')];

      // Mock repository to return null (no previous emails)
      (mockPrisma.gmailMessage.findFirst as jest.Mock).mockResolvedValue(null);

      // Mock fetcher to return emails without date filter
      mockEmailFetcher.fetchEmails.mockResolvedValue(mockEmails);

      // Mock transaction
      (mockPrisma.$transaction as jest.Mock).mockImplementation((operations) => {
        return Promise.all(operations.map(() => Promise.resolve()));
      });

      const result = await fetchAndPersistEmails({
        gmailClient: mockGmailClient,
        emailFetcher: mockEmailFetcher,
        repository,
      });

      // Verify no timestamp filter was used
      expect(mockEmailFetcher.fetchEmails).toHaveBeenCalled();
      expect(mockEmailFetcher.fetchEmailsSince).not.toHaveBeenCalled();

      // Verify result
      expect(result.success).toBe(true);
      expect(result.sinceTimestamp).toBeNull();
    });

    it('should use custom --since date if provided', async () => {
      const customSince = new Date('2024-01-01T00:00:00Z');
      const mockEmails: EmailMessage[] = [createMockEmail('msg1', 'thread1', 'test@example.com')];

      mockEmailFetcher.fetchEmailsSince.mockResolvedValue(mockEmails);

      (mockPrisma.$transaction as jest.Mock).mockImplementation((operations) => {
        return Promise.all(operations.map(() => Promise.resolve()));
      });

      const result = await fetchAndPersistEmails({
        gmailClient: mockGmailClient,
        emailFetcher: mockEmailFetcher,
        repository,
        sinceDate: customSince,
      });

      // Should skip database timestamp query and use custom date
      expect(mockPrisma.gmailMessage.findFirst).not.toHaveBeenCalled();
      expect(mockEmailFetcher.fetchEmailsSince).toHaveBeenCalledWith(customSince);
      expect(result.sinceTimestamp).toEqual(customSince);
    });
  });

  describe('Error Handling', () => {
    it('should handle Gmail authentication errors', async () => {
      mockGmailClient.isAuthenticated.mockReturnValue(false);

      const result = await fetchAndPersistEmails({
        gmailClient: mockGmailClient,
        emailFetcher: mockEmailFetcher,
        repository,
      });

      expect(result.success).toBe(false);
      expect(result.errors).toContainEqual(
        expect.objectContaining({
          type: 'authentication',
          message: expect.stringContaining('not authenticated'),
        })
      );
    });

    it('should handle Gmail API fetch errors', async () => {
      (mockPrisma.gmailMessage.findFirst as jest.Mock).mockResolvedValue(null);

      const apiError = new Error('Gmail API quota exceeded');
      mockEmailFetcher.fetchEmails.mockRejectedValue(apiError);

      const result = await fetchAndPersistEmails({
        gmailClient: mockGmailClient,
        emailFetcher: mockEmailFetcher,
        repository,
      });

      expect(result.success).toBe(false);
      expect(result.errors).toContainEqual(
        expect.objectContaining({
          type: 'fetch',
          message: expect.stringContaining('Gmail API quota exceeded'),
        })
      );
    });

    it('should handle database persistence errors', async () => {
      const mockEmails: EmailMessage[] = [createMockEmail('msg1', 'thread1', 'test@example.com')];

      (mockPrisma.gmailMessage.findFirst as jest.Mock).mockResolvedValue(null);
      mockEmailFetcher.fetchEmails.mockResolvedValue(mockEmails);

      const dbError = new Error('Database connection timeout');
      (mockPrisma.$transaction as jest.Mock).mockRejectedValue(dbError);

      const result = await fetchAndPersistEmails({
        gmailClient: mockGmailClient,
        emailFetcher: mockEmailFetcher,
        repository,
      });

      expect(result.success).toBe(false);
      expect(result.errors).toContainEqual(
        expect.objectContaining({
          type: 'persistence',
          message: expect.stringContaining('Database connection timeout'),
        })
      );
    });

    it('should handle partial failures gracefully', async () => {
      const mockEmails: EmailMessage[] = [
        createMockEmail('msg1', 'thread1', 'test1@example.com'),
        createMockEmail('msg2', 'thread2', 'test2@example.com'),
      ];

      (mockPrisma.gmailMessage.findFirst as jest.Mock).mockResolvedValue(null);
      mockEmailFetcher.fetchEmails.mockResolvedValue(mockEmails);

      // Mock transaction to partially fail
      (mockPrisma.$transaction as jest.Mock).mockRejectedValue(new Error('Unique constraint violation'));

