  });

  describe('Batch Processing', () => {
    it('should handle large batches efficiently', async () => {
      const largeEmailBatch: EmailMessage[] = Array.from({ length: 100 }, (_, i) =>
        createMockEmail(`msg${i}`, `thread${i}`, `test${i}@example.com`)
      );

